import React from 'react';

type PageLayoutProps = {
  children: React.ReactNode;
  className?: string;
  contentClassName?: string;
};

const PageLayout: React.FC<PageLayoutProps> = ({ children, className = '', contentClassName = '' }) => {
  return (
    <div className={`box-border w-full min-h-screen px-[1in] py-[1in] ${className}`}>
      <div className={`mx-auto flex min-h-[calc(100vh-2in)] w-full max-w-[1280px] flex-col space-y-20 ${contentClassName}`}>
        {children}
      </div>
    </div>
  );
};

export default PageLayout;
